import React, { useState, useEffect, useRef } from 'react';
import './App.css';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import AuthPage from './components/AuthPage';
import ProjectList from './components/ProjectList';
import ProjectView from './components/ProjectView';
import UserMenu from './components/UserMenu';
import InvitesBanner from './components/InvitesBanner';
import Footer from './components/Footer';
import { getGreeting } from './utils/greeting';
import { useProjects } from './hooks/useProjects';
import { Cpu } from 'lucide-react';

export default function App() {
  return (
    <AuthProvider>
      <AppInner />
    </AuthProvider>
  );
}

function AppInner() {
  const { currentUser, loading } = useAuth();

  if (loading) return <Splash />;
  if (!currentUser) return <AuthPage />;
  return <MainApp />;
}

function MainApp() {
  const { currentUser } = useAuth();
  const { projects, loading } = useProjects(currentUser?.uid);
  const [activeProjectId, setActiveProjectId] = useState(null);
  const [greeting] = useState(() => getGreeting(currentUser?.displayName));

  const activeProject = projects.find(p => p.id === activeProjectId) || null;

  // If active project was deleted or access revoked, go home
  useEffect(() => {
    if (activeProjectId && !loading && !activeProject) {
      setActiveProjectId(null);
    }
  }, [activeProject, activeProjectId, loading]);

  return (
    <div className="app-shell">
      <Header
        onHome={() => setActiveProjectId(null)}
        activeProject={activeProject}
        greeting={greeting}
      />
      <InvitesBanner />
      <main className="app-main">
        {!activeProject ? (
          <ProjectList
            projects={projects}
            loading={loading}
            currentUser={currentUser}
            onSelect={setActiveProjectId}
          />
        ) : (
          <ProjectView
            project={activeProject}
            currentUser={currentUser}
            onBack={() => setActiveProjectId(null)}
          />
        )}
      </main>
      <Footer />
    </div>
  );
}

function Header({ onHome, activeProject, greeting }) {
  return (
    <header className="app-header">
      <div className="header-inner">
        <button className="logo-btn" onClick={onHome}>
          <span className="logo-icon">৳</span>
          <span className="logo-text">Taka<strong>Tracker</strong></span>
        </button>

        {activeProject && (
          <div className="header-breadcrumb">
            <span className="breadcrumb-sep">/</span>
            <span className="breadcrumb-name">{activeProject.name}</span>
          </div>
        )}

        <div className="header-right">
          {greeting && !activeProject && (
            <span className="header-greeting">{greeting}</span>
          )}
          <div className="header-tag mono">Plan Shopping</div>
          <UserMenu />
        </div>
      </div>
    </header>
  );
}

function Splash() {
  return (
    <div className="splash">
      <div className="splash-logo">
        <span>৳</span>
      </div>
      <p className="splash-text mono pulse">Loading...</p>
    </div>
  );
}
