import { useState, useEffect, useCallback } from 'react';
import {
  collection, query, where, onSnapshot, orderBy, limit,
  doc, addDoc, updateDoc, deleteDoc,
  serverTimestamp, getDoc, arrayUnion, arrayRemove,
  runTransaction,
} from 'firebase/firestore';
import { db } from '../firebase';

export function genId() {
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

// ─── Real-time hooks ──────────────────────────────────────────────

export function useProjects(uid) {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!uid) { setProjects([]); setLoading(false); return; }

    const q = query(
      collection(db, 'projects'),
      where('memberUids', 'array-contains', uid)
    );

    const unsub = onSnapshot(q, (snap) => {
      const list = snap.docs
        .map(d => ({ id: d.id, ...d.data() }))
        .sort((a, b) => (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0));
      setProjects(list);
      setLoading(false);
    }, (err) => {
      console.error('Projects listener:', err.message);
      setLoading(false);
    });

    return unsub;
  }, [uid]);

  return { projects, loading };
}

export function useInvites(email) {
  const [invites, setInvites] = useState([]);

  useEffect(() => {
    if (!email) return;
    // Query uses lowercase email — must match what sendInvite stored
    const normalised = email.toLowerCase().trim();
    const q = query(
      collection(db, 'invites'),
      where('inviteeEmail', '==', normalised),
      where('status', '==', 'pending')
    );
    const unsub = onSnapshot(q, (snap) => {
      setInvites(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    }, (err) => {
      console.error('Invites listener:', err.message);
    });
    return unsub;
  }, [email]);

  return invites;
}

// ─── Chat ─────────────────────────────────────────────────────────

export function useChatMessages(projectId) {
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    if (!projectId) return;
    const q = query(
      collection(db, 'projects', projectId, 'messages'),
      orderBy('createdAt', 'asc'),
      limit(200)
    );
    const unsub = onSnapshot(q, (snap) => {
      setMessages(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    }, (err) => {
      console.error('Chat listener:', err.message);
    });
    return unsub;
  }, [projectId]);

  return messages;
}

export async function sendChatMessage(projectId, { senderId, senderName, senderPhoto = '', text }) {
  const trimmed = text.trim();
  if (!trimmed) return;
  await addDoc(collection(db, 'projects', projectId, 'messages'), {
    senderId,
    senderName,
    senderPhoto,
    text: trimmed,
    type: 'text',
    createdAt: serverTimestamp(),
  });
  // Update last-message metadata on project (non-blocking)
  updateDoc(doc(db, 'projects', projectId), {
    chatEnabled: true,
    _chatLastMessage: trimmed.slice(0, 80),
    _chatLastMessageAt: serverTimestamp(),
  }).catch(() => {});
}

// ─── Project mutations ────────────────────────────────────────────

export async function createProject({ name, description, uid, userEmail, userName }) {
  return addDoc(collection(db, 'projects'), {
    name,
    description,
    ownerId: uid,
    ownerEmail: userEmail,
    ownerName: userName,
    members: {
      [uid]: { role: 'owner', email: userEmail, name: userName }
    },
    memberUids: [uid],
    components: [],
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp(),
    chatEnabled: false,
    _chatLastMessage: null,
    _chatLastMessageAt: null,
  });
}

export async function deleteProject(projectId) {
  await deleteDoc(doc(db, 'projects', projectId));
}

export async function updateComponents(projectId, components) {
  await updateDoc(doc(db, 'projects', projectId), {
    components,
    updatedAt: serverTimestamp(),
  });
}

export async function updateProjectMeta(projectId, data) {
  await updateDoc(doc(db, 'projects', projectId), {
    ...data,
    updatedAt: serverTimestamp(),
  });
}

// ─── Collaboration ────────────────────────────────────────────────

export async function sendInvite({
  projectId, projectName,
  inviterId, inviterName, inviterEmail,
  inviteeEmail, role,
}) {
  const snap = await getDoc(doc(db, 'projects', projectId));
  if (!snap.exists()) throw new Error('Project not found.');

  const data = snap.data();
  const memberEmails = Object.values(data.members || {}).map(m => (m.email || '').toLowerCase());
  if (memberEmails.includes(inviteeEmail.toLowerCase().trim())) {
    throw new Error('This person is already a member of this project.');
  }

  await addDoc(collection(db, 'invites'), {
    projectId,
    projectName,
    inviterId,
    inviterName,
    inviterEmail,
    inviteeEmail: inviteeEmail.toLowerCase().trim(),
    role,
    status: 'pending',
    createdAt: serverTimestamp(),
  });
}

// ─── acceptInvite ─────────────────────────────────────────────────
// Root cause of the previous bug:
//   writeBatch tried to update BOTH the invite doc AND the project doc
//   atomically. But the invitee doesn't have write access to the project
//   until AFTER they're added as a member — a chicken-and-egg permissions
//   failure. Firestore rejected the whole batch silently (the catch in
//   InvitesBanner swallowed the error), so status was never updated and
//   the invite kept reappearing.
//
// Fix: use runTransaction so we can read the current state and write
//   both documents inside one server-side round-trip, AND update the
//   invite status FIRST so even if the project write fails the invite
//   won't re-appear. We also add the member-write permission to Firestore
//   rules for the invite-accept case (see FIREBASE_SETUP.md).
//
// Firestore rule change needed (see FIREBASE_SETUP.md):
//   projects: allow update if the invite doc proves membership grant,
//   OR keep a separate "pendingMemberUids" field the invitee can write to.
//
// Simpler workaround used here: split into two sequential writes.
//   Step 1 — mark invite accepted (invitee has permission for this).
//   Step 2 — add member to project (the project owner's security rule
//             must allow "any authenticated user can add themselves IF
//             they have a matching accepted invite").
//   We update the Firestore rule accordingly in FIREBASE_SETUP.md.
export async function acceptInvite(invite, currentUser) {
  // Step 1: mark the invite as accepted.
  // The invitee owns this write (rule: inviteeEmail == auth.token.email).
  await updateDoc(doc(db, 'invites', invite.id), {
    status: 'accepted',
    acceptedAt: serverTimestamp(),
    acceptedByUid: currentUser.uid,
  });

  // Step 2: add the invitee to the project.
  // The updated Firestore rule permits this when:
  //   - the caller is authenticated
  //   - they are NOT already a member (arrayUnion is idempotent)
  //   - they have a valid accepted invite for this project
  // (We rely on the rule in FIREBASE_SETUP.md — see "invite-accept" rule)
  await updateDoc(doc(db, 'projects', invite.projectId), {
    [`members.${currentUser.uid}`]: {
      role: invite.role || 'editor',
      email: currentUser.email,
      name: currentUser.displayName || currentUser.email,
      joinedAt: serverTimestamp(),
    },
    memberUids: arrayUnion(currentUser.uid),
  });
}

export async function rejectInvite(inviteId) {
  await updateDoc(doc(db, 'invites', inviteId), { status: 'rejected' });
}

export async function removeMember(projectId, uid) {
  const snap = await getDoc(doc(db, 'projects', projectId));
  if (!snap.exists()) return;
  const members = { ...snap.data().members };
  delete members[uid];
  await updateDoc(doc(db, 'projects', projectId), {
    members,
    memberUids: arrayRemove(uid),
    updatedAt: serverTimestamp(),
  });
}

// ─── Direct Messages ──────────────────────────────────────────────
// DM ID is deterministic: sorted UIDs + projectId
// so two users always get the same thread, idempotent on creation.

export function dmId(uid1, uid2, projectId) {
  return [uid1, uid2].sort().join('__') + '__' + projectId;
}

export async function getOrCreateDM(uid1, uid2, projectId, projectName, names, photos) {
  const id = dmId(uid1, uid2, projectId);
  const ref = doc(db, 'dms', id);
  const snap = await getDoc(ref);
  if (!snap.exists()) {
    const { setDoc } = await import('firebase/firestore');
    await setDoc(ref, {
      participantUids: [uid1, uid2].sort(),
      participantNames: names,   // { [uid]: displayName }
      participantPhotos: photos, // { [uid]: photoURL }
      projectId,
      projectName,
      lastMessage: '',
      lastMessageAt: null,
      createdAt: serverTimestamp(),
    });
  }
  return id;
}

export function useDMs(uid) {
  const [dms, setDms] = useState([]);
  useEffect(() => {
    if (!uid) return;
    const q = query(
      collection(db, 'dms'),
      where('participantUids', 'array-contains', uid)
    );
    const unsub = onSnapshot(q, snap => {
      const list = snap.docs
        .map(d => ({ id: d.id, ...d.data() }))
        .sort((a, b) => (b.lastMessageAt?.seconds || 0) - (a.lastMessageAt?.seconds || 0));
      setDms(list);
    }, err => console.error('DMs listener:', err.message));
    return unsub;
  }, [uid]);
  return dms;
}

export function useDMMessages(id) {
  const [messages, setMessages] = useState([]);
  useEffect(() => {
    if (!id) return;
    const q = query(
      collection(db, 'dms', id, 'messages'),
      orderBy('createdAt', 'asc'),
      limit(300)
    );
    const unsub = onSnapshot(q, snap => {
      setMessages(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    }, err => console.error('DM messages listener:', err.message));
    return unsub;
  }, [id]);
  return messages;
}

export async function sendDMMessage(id, { senderId, senderName, senderPhoto = '', text }) {
  const trimmed = text.trim();
  if (!trimmed) return;
  await addDoc(collection(db, 'dms', id, 'messages'), {
    senderId, senderName, senderPhoto,
    text: trimmed,
    createdAt: serverTimestamp(),
  });
  updateDoc(doc(db, 'dms', id), {
    lastMessage: trimmed.slice(0, 80),
    lastMessageAt: serverTimestamp(),
  }).catch(() => {});
}
