import React, { useState, useRef, useEffect } from 'react';
import { Send, X, Zap, Check, ChevronDown, AlertCircle } from 'lucide-react';
import './GeminiPanel.css';

const GEMINI_KEY = 'AIzaSyDhX9NPtS7P8sW2S8oCJExAZub0p-nP_KI';
const GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_KEY}`;

const SYSTEM = `You are the Build Advisor inside Taka Tracker — an app for robotics builders in Bangladesh. You help people plan their component shopping lists (called BOMs).

Your vibe: gen-Z energy, but you're the smart one who actually ships. Not cringe, not "bestie", not "slay". Think: chill, direct, technically sharp. Match the user's energy. Use metric units. Prices in BDT (Taka, ৳).

You can do two things:
1. Chat — answer questions, explain specs, suggest builds, give trade-offs
2. Edit the list — add, update, or remove components in the user's project

When you want to make list changes, ALWAYS explain in plain text first, then end your message with a JSON block in EXACTLY this format (no extra text after the block):

\`\`\`action
{
  "type": "add" | "update" | "delete",
  "components": [
    {
      "id": "only_for_update_or_delete",
      "name": "Component Name",
      "quantity": 1,
      "category": "MCU|Motor|Sensor|ESC|Power|Frame|Accessory|Other",
      "notes": "short technical note — why it's good, key spec"
    }
  ]
}
\`\`\`

Rules:
- For "add": omit "id". New items get IDs automatically.
- For "update": include "id" from the existing component list provided in context.
- For "delete": only include "id" and "name" in each component.
- Never silently edit. Always explain before the action block.
- Keep notes short (1-2 sentences max).
- If unsure what the user wants, ask ONE clarifying question.
- No hallucinating specs. If you don't know a spec, say so.`;

function buildContext(project) {
  if (!project?.components?.length) return 'The project list is currently empty.';
  const lines = project.components.map(c =>
    `- [id:${c.id}] ${c.name} ×${c.quantity || 1}${c.category ? ` (${c.category})` : ''}${c.notes ? ` | ${c.notes}` : ''}`
  );
  return `Current list for "${project.name}":\n${lines.join('\n')}`;
}

function parseAction(text) {
  const match = text.match(/```action\s*([\s\S]*?)```/);
  if (!match) return null;
  try {
    const parsed = JSON.parse(match[1].trim());
    if (parsed.type && Array.isArray(parsed.components)) return parsed;
    return null;
  } catch { return null; }
}

function stripAction(text) {
  return text.replace(/```action[\s\S]*?```/g, '').trim();
}

export default function GeminiPanel({ project, canEdit, onApplyAction, onClose }) {
  const [history, setHistory] = useState([]);    // { role, parts:[{text}] }[]
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [pendingAction, setPendingAction] = useState(null);
  const [appliedIds, setAppliedIds] = useState(new Set());
  const [error, setError] = useState('');
  const [atBottom, setAtBottom] = useState(true);
  const bottomRef = useRef(null);
  const scrollRef = useRef(null);
  const inputRef = useRef(null);
  const msgIdCounter = useRef(0);

  useEffect(() => { inputRef.current?.focus(); }, []);
  useEffect(() => {
    if (atBottom) bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history, loading, atBottom]);

  function handleScroll() {
    const el = scrollRef.current;
    if (!el) return;
    setAtBottom(el.scrollHeight - el.scrollTop - el.clientHeight < 60);
  }

  async function sendMessage(userText) {
    const text = (userText || input).trim();
    if (!text || loading) return;
    setInput('');
    setError('');

    const contextNote = `[Context] ${buildContext(project)}\n\n[User message] ${text}`;
    const newHistory = [
      ...history,
      { role: 'user', parts: [{ text: contextNote }], _display: text, _id: ++msgIdCounter.current },
    ];
    setHistory(newHistory);
    setLoading(true);

    try {
      const payload = {
        system_instruction: { parts: [{ text: SYSTEM }] },
        contents: newHistory.map(({ role, parts }) => ({ role, parts })),
        generationConfig: { temperature: 0.85, maxOutputTokens: 1200 },
      };
      const res = await fetch(GEMINI_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);

      const raw = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
      const action = parseAction(raw);
      const display = stripAction(raw);
      const msgId = ++msgIdCounter.current;

      setHistory(h => [
        ...h,
        { role: 'model', parts: [{ text: raw }], _display: display, _action: action, _id: msgId },
      ]);
      if (action && canEdit) setPendingAction({ action, msgId });
    } catch (e) {
      setError(e.message || 'Gemini is offline rn. Try again.');
    }
    setLoading(false);
  }

  function handleApply(msgId, action) {
    onApplyAction(action);
    setAppliedIds(s => new Set([...s, msgId]));
    setPendingAction(null);
  }

  function handleKey(e) {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  }

  const starters = [
    'Suggest components for a 500g quadcopter',
    'What ESC do I need for 1000KV motors?',
    'Add MPU-6050 and a 3S LiPo battery',
    'Explain KV rating to me',
  ];

  return (
    <div className="gp-root fade-in">
      <div className="gp-header">
        <div className="gp-header-left">
          <div className="gp-icon"><Zap size={13} /></div>
          <span className="gp-title">Build Advisor</span>
          <span className="gp-badge">Gemini</span>
        </div>
        <button className="gp-close" onClick={onClose}><X size={16} /></button>
      </div>

      <div className="gp-messages" ref={scrollRef} onScroll={handleScroll}>
        {history.length === 0 && (
          <div className="gp-empty">
            <div className="gp-empty-icon"><Zap size={28} /></div>
            <p className="gp-empty-title">What are we building?</p>
            <p className="gp-empty-sub">Ask me anything — specs, trade-offs, full BOM, or just vibe check your component list.</p>
            <div className="gp-starters">
              {starters.map((s, i) => (
                <button key={i} className="gp-starter" onClick={() => sendMessage(s)}>{s}</button>
              ))}
            </div>
          </div>
        )}

        {history.map((msg) => {
          const isUser = msg.role === 'user';
          const isApplied = appliedIds.has(msg._id);
          return (
            <div key={msg._id} className={`gp-msg ${isUser ? 'gp-msg-user' : 'gp-msg-ai'}`}>
              {!isUser && <div className="gp-ai-avatar"><Zap size={11} /></div>}
              <div className="gp-bubble-col">
                <div className={`gp-bubble ${isUser ? 'gp-bubble-user' : 'gp-bubble-ai'}`}>
                  <MessageText text={msg._display} />
                </div>

                {/* Action preview card */}
                {!isUser && msg._action && canEdit && (
                  <div className={`gp-action-card ${isApplied ? 'gp-action-applied' : ''}`}>
                    <div className="gp-action-header">
                      <span className="gp-action-type">
                        {msg._action.type === 'add' ? '➕ Add to list' : msg._action.type === 'update' ? '✏️ Update list' : '🗑️ Remove from list'}
                      </span>
                      <span className="gp-action-count">{msg._action.components.length} item{msg._action.components.length !== 1 ? 's' : ''}</span>
                    </div>
                    <div className="gp-action-items">
                      {msg._action.components.map((c, i) => (
                        <div key={i} className="gp-action-item">
                          <span className="gp-action-name">{c.name}</span>
                          {c.quantity > 1 && <span className="gp-action-qty">×{c.quantity}</span>}
                          {c.category && <span className="gp-action-cat">{c.category}</span>}
                        </div>
                      ))}
                    </div>
                    {isApplied ? (
                      <div className="gp-action-done"><Check size={12} /> Applied to list</div>
                    ) : (
                      <div className="gp-action-btns">
                        <button className="gp-apply-btn" onClick={() => handleApply(msg._id, msg._action)}>
                          <Check size={12} /> Apply
                        </button>
                        <button className="gp-dismiss-btn" onClick={() => setPendingAction(null)}>
                          Dismiss
                        </button>
                      </div>
                    )}
                  </div>
                )}
                {!isUser && msg._action && !canEdit && (
                  <div className="gp-action-card gp-action-readonly">
                    <span>You're a viewer — can't apply changes</span>
                  </div>
                )}
              </div>
            </div>
          );
        })}

        {loading && (
          <div className="gp-msg gp-msg-ai">
            <div className="gp-ai-avatar"><Zap size={11} /></div>
            <div className="gp-thinking">
              <span /><span /><span />
            </div>
          </div>
        )}

        {error && (
          <div className="gp-error"><AlertCircle size={13} /> {error}</div>
        )}

        <div ref={bottomRef} />
      </div>

      {!atBottom && (
        <button className="gp-scroll-btn" onClick={() => { bottomRef.current?.scrollIntoView({ behavior:'smooth' }); setAtBottom(true); }}>
          <ChevronDown size={13} />
        </button>
      )}

      <div className="gp-input-row">
        <textarea
          ref={inputRef}
          className="gp-input"
          placeholder="Ask anything or say 'add 4 motors 1000KV'..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={handleKey}
          rows={1}
          maxLength={800}
          disabled={loading}
        />
        <button className="gp-send" onClick={() => sendMessage()} disabled={!input.trim() || loading}>
          <Send size={14} />
        </button>
      </div>
    </div>
  );
}

// Renders AI text with basic markdown: **bold**, `code`, newlines
function MessageText({ text }) {
  if (!text) return null;
  const lines = text.split('\n');
  return (
    <span>
      {lines.map((line, i) => {
        // bold
        const parts = line.split(/(\*\*[^*]+\*\*|`[^`]+`)/g);
        return (
          <React.Fragment key={i}>
            {parts.map((p, j) => {
              if (p.startsWith('**') && p.endsWith('**')) return <strong key={j}>{p.slice(2, -2)}</strong>;
              if (p.startsWith('`') && p.endsWith('`')) return <code key={j} className="gp-code">{p.slice(1, -1)}</code>;
              return p;
            })}
            {i < lines.length - 1 && <br />}
          </React.Fragment>
        );
      })}
    </span>
  );
}
