import React, { useState, useRef, useEffect } from 'react';
import { LogOut, User, ChevronDown } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import './UserMenu.css';

export default function UserMenu() {
  const { currentUser, signOut } = useAuth();
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    function handler(e) { if (ref.current && !ref.current.contains(e.target)) setOpen(false); }
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const name = currentUser?.displayName || currentUser?.email || 'User';
  const initial = name[0].toUpperCase();
  const photo = currentUser?.photoURL;

  return (
    <div className="um-root" ref={ref}>
      <button className="um-trigger" onClick={() => setOpen(o => !o)}>
        <div className="um-avatar">
          {photo ? <img src={photo} alt={name} className="um-photo" referrerPolicy="no-referrer" /> : initial}
        </div>
        <ChevronDown size={13} className={`um-chevron ${open ? 'open' : ''}`} />
      </button>

      {open && (
        <div className="um-dropdown fade-in">
          <div className="um-user-info">
            <div className="um-avatar um-avatar-lg">
              {photo ? <img src={photo} alt={name} className="um-photo" referrerPolicy="no-referrer" /> : initial}
            </div>
            <div>
              <div className="um-name">{currentUser?.displayName || 'User'}</div>
              <div className="um-email">{currentUser?.email}</div>
            </div>
          </div>
          <div className="um-divider" />
          <button className="um-item um-signout" onClick={signOut}>
            <LogOut size={14} /> Sign out
          </button>
        </div>
      )}
    </div>
  );
}
