import React, { useState } from 'react';
import { Bell, Check, X, AlertCircle } from 'lucide-react';
import { useInvites, acceptInvite, rejectInvite } from '../hooks/useProjects';
import { useAuth } from '../contexts/AuthContext';
import './InvitesBanner.css';

export default function InvitesBanner() {
  const { currentUser } = useAuth();
  const invites = useInvites(currentUser?.email);
  const [busy, setBusy] = useState({});
  const [errors, setErrors] = useState({});
  const [dismissed, setDismissed] = useState({});

  if (!invites.length) return null;
  const visible = invites.filter(inv => !dismissed[inv.id]);
  if (!visible.length) return null;

  async function handleAccept(inv) {
    setBusy(b => ({ ...b, [inv.id]: 'accepting' }));
    setErrors(e => ({ ...e, [inv.id]: null }));
    try {
      await acceptInvite(inv, currentUser);
      // Dismiss after small delay so user sees the success state
      setTimeout(() => setDismissed(d => ({ ...d, [inv.id]: true })), 600);
    } catch (e) {
      console.error('acceptInvite error:', e);
      setErrors(err => ({ ...err, [inv.id]: 'Failed to accept. Please try again.' }));
    }
    setBusy(b => ({ ...b, [inv.id]: null }));
  }

  async function handleReject(inv) {
    setBusy(b => ({ ...b, [inv.id]: 'rejecting' }));
    try {
      await rejectInvite(inv.id);
    } catch {}
    setDismissed(d => ({ ...d, [inv.id]: true }));
    setBusy(b => ({ ...b, [inv.id]: null }));
  }

  return (
    <div className="ib-root">
      <div className="ib-inner">
        <div className="ib-icon-wrap"><Bell size={14} /></div>
        <div className="ib-invites">
          {visible.map(inv => (
            <div key={inv.id} className="ib-invite slide-in">
              <span className="ib-text">
                <strong>{inv.inviterName || inv.inviterEmail}</strong> invited you to&nbsp;
                <span className="ib-project-name">"{inv.projectName}"</span>
                &nbsp;as <span className="ib-role">{inv.role}</span>
              </span>
              {errors[inv.id] && (
                <span className="ib-error">
                  <AlertCircle size={11} /> {errors[inv.id]}
                </span>
              )}
              <div className="ib-actions">
                <button
                  className={`ib-accept ${busy[inv.id] === 'accepting' ? 'ib-accepting' : ''}`}
                  onClick={() => handleAccept(inv)}
                  disabled={!!busy[inv.id]}
                >
                  {busy[inv.id] === 'accepting'
                    ? <span className="ib-spinner" />
                    : <><Check size={12} /> Accept</>}
                </button>
                <button
                  className="ib-reject"
                  onClick={() => handleReject(inv)}
                  disabled={!!busy[inv.id]}
                >
                  <X size={12} />
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
