import React, { useState, useMemo, useCallback, useRef } from 'react';
import { ArrowLeft, Plus, Download, Store, ShoppingCart, Check, AlertCircle, Users, Lock, MessageCircle, Zap } from 'lucide-react';
import ComponentRow from './ComponentRow';
import ExportCard from './ExportCard';
import CollabModal from './CollabModal';
import { updateComponents } from '../hooks/useProjects';
import ChatPanel from './ChatPanel';
import GeminiPanel from './GeminiPanel';
import './ProjectView.css';

function genId() { return Math.random().toString(36).slice(2) + Date.now().toString(36); }

const STORES = ['TechshopBD', 'RoboticsBD', 'StarTech', 'UltraTech', 'RyansComputers', 'DarazBD', 'AliExpress', 'Custom'];

// Debounce save to Firestore — batches rapid edits
function useDebounce(fn, delay) {
  const timer = useRef(null);
  return useCallback((...args) => {
    clearTimeout(timer.current);
    timer.current = setTimeout(() => fn(...args), delay);
  }, [fn, delay]);
}

export default function ProjectView({ project, currentUser, onBack }) {
  const [components, setComponents] = useState(project.components || []);
  const [adding, setAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newQty, setNewQty] = useState(1);
  const [newCat, setNewCat] = useState('');
  const [globalStore, setGlobalStore] = useState('');
  const [showExport, setShowExport] = useState(false);
  const [showCollab, setShowCollab] = useState(false);
  const [panel, setPanel] = useState(null); // null | 'chat' | 'ai'
  const [filterCat, setFilterCat] = useState('');
  const [saveStatus, setSaveStatus] = useState('saved'); // 'saved' | 'saving' | 'error'

  // Keep components in sync if project prop updates (other members editing)
  React.useEffect(() => {
    setComponents(project.components || []);
  }, [project.components]);

  const memberRole = project.members?.[currentUser.uid]?.role || 'viewer';
  const canEdit = memberRole === 'owner' || memberRole === 'editor';
  const isOwner = project.ownerId === currentUser.uid;

  // Persist to Firestore with debounce
  const saveToFirestore = useCallback(async (comps) => {
    setSaveStatus('saving');
    try {
      await updateComponents(project.id, comps);
      setSaveStatus('saved');
    } catch {
      setSaveStatus('error');
    }
  }, [project.id]);

  const debouncedSave = useDebounce(saveToFirestore, 800);

  function setAndSave(newComps) {
    setComponents(newComps);
    debouncedSave(newComps);
  }

  function addComponent() {
    if (!newName.trim() || !canEdit) return;
    const comp = {
      id: genId(),
      name: newName.trim(),
      quantity: parseInt(newQty) || 1,
      category: newCat.trim(),
      prices: [],
      selectedStore: '',
      notes: '',
      checked: false,
    };
    const updated = [...components, comp];
    setAndSave(updated);
    setNewName(''); setNewQty(1); setNewCat(''); setAdding(false);
  }

  function updateComponent(id, changes) {
    const updated = components.map(c => c.id === id ? { ...c, ...changes } : c);
    setAndSave(updated);
  }

  function deleteComponent(id) {
    const updated = components.filter(c => c.id !== id);
    setAndSave(updated);
  }

  // Summary
  const { totalSelected, totalMin, totalMax, allStores, completeness } = useMemo(() => {
    let totalSelected = 0, totalMin = 0, totalMax = 0;
    const storeSet = new Set();
    let withPrice = 0;

    for (const comp of components) {
      const qty = comp.quantity || 1;
      if (comp.prices?.length > 0) {
        withPrice++;
        const prices = comp.prices.map(p => p.price).filter(p => p > 0);
        if (prices.length > 0) {
          totalMin += Math.min(...prices) * qty;
          totalMax += Math.max(...prices) * qty;
        }
        const storeKey = globalStore || comp.selectedStore;
        const match = storeKey ? comp.prices.find(p => p.store === storeKey) : null;
        totalSelected += (match ? match.price : (prices.length ? Math.min(...prices) : 0)) * qty;
        comp.prices.forEach(p => storeSet.add(p.store));
      }
    }

    return {
      totalSelected, totalMin, totalMax,
      allStores: [...storeSet].sort(),
      completeness: components.length > 0 ? Math.round((withPrice / components.length) * 100) : 0,
    };
  }, [components, globalStore]);

  const categories = useMemo(() => {
    const cats = new Set(components.map(c => c.category).filter(Boolean));
    return [...cats].sort();
  }, [components]);

  const filteredComponents = useMemo(() => {
    if (!filterCat) return components;
    return components.filter(c => c.category === filterCat);
  }, [components, filterCat]);

  const checkedCount = components.filter(c => c.checked).length;
  const memberCount = Object.keys(project.members || {}).length;

  return (
    <div className={`pv-root fade-in ${panel ? "pv-with-chat" : ""}`}>
      <div className="pv-content">
      {/* Top bar */}
      <div className="pv-topbar">
        <button className="pv-back-btn" onClick={onBack}><ArrowLeft size={16} /> Projects</button>
        <div className="pv-title-block">
          <div className="pv-title-row">
            <h1 className="pv-title">{project.name}</h1>
            <div className={`pv-save-dot ${saveStatus}`} title={saveStatus === 'saved' ? 'All changes saved' : saveStatus === 'saving' ? 'Saving...' : 'Save error'} />
          </div>
          {project.description && <p className="pv-desc">{project.description}</p>}
          <div className="pv-owner-row">
            <span className="pv-owner-label">by {project.ownerName || project.ownerEmail}</span>
            {!canEdit && <span className="pv-viewer-badge"><Lock size={10} /> View only</span>}
          </div>
        </div>
        <div className="pv-topbar-actions">
          <button className={`btn-chat ${panel === "ai" ? "btn-panel-active btn-panel-ai" : ""}`} onClick={() => setPanel(p => p === "ai" ? null : "ai")} title="AI Advisor">
            <Zap size={14} /> {panel === "ai" ? "Close AI" : "AI Advisor"}
          </button>
          <button className={`btn-chat ${panel === "chat" ? "btn-panel-active" : ""}`} onClick={() => setPanel(p => p === "chat" ? null : "chat")} title="Team Chat">
            <MessageCircle size={14} /> {panel === "chat" ? "Close Chat" : "Chat"}
          </button>
          <button className="btn-collab" onClick={() => setShowCollab(true)}>
            <Users size={14} />
            {memberCount > 1 ? `${memberCount} members` : 'Share'}
          </button>
          <button className="btn-export" onClick={() => setShowExport(true)}>
            <Download size={15} /> Export
          </button>
        </div>
      </div>

      {/* Summary cards */}
      <div className="pv-summary-row">
        <div className="pv-sum-card">
          <div className="pv-sum-label mono">ESTIMATED TOTAL</div>
          <div className="pv-sum-value accent mono">৳{totalSelected.toLocaleString('en-BD')}</div>
          {totalMin !== totalMax && (
            <div className="pv-sum-range">৳{totalMin.toLocaleString()} – ৳{totalMax.toLocaleString()}</div>
          )}
        </div>
        <div className="pv-sum-card">
          <div className="pv-sum-label mono">COMPONENTS</div>
          <div className="pv-sum-value mono">{components.length}</div>
          <div className="pv-sum-range">{checkedCount} purchased</div>
        </div>
        <div className="pv-sum-card">
          <div className="pv-sum-label mono">PRICE COVERAGE</div>
          <div className="pv-sum-value mono" style={{ color: completeness === 100 ? 'var(--accent3)' : completeness > 50 ? 'var(--accent)' : completeness > 0 ? 'var(--danger)' : 'var(--text3)' }}>
            {completeness}%
          </div>
          <div className="pv-sum-range">components with prices</div>
        </div>
        <div className="pv-sum-card pv-store-picker">
          <div className="pv-sum-label mono">EVALUATE BY STORE</div>
          <div className="pv-store-sel-wrap">
            <Store size={14} className="pv-store-icon" />
            <select value={globalStore} onChange={e => setGlobalStore(e.target.value)} className="pv-store-select">
              <option value="">Best price (auto)</option>
              {STORES.map(s => <option key={s} value={s}>{s}</option>)}
              {allStores.filter(s => !STORES.includes(s)).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          {globalStore && (
            <div className="pv-sum-range" style={{ color: 'var(--accent3)' }}>
              Total from {globalStore}: ৳{totalSelected.toLocaleString()}
            </div>
          )}
        </div>
      </div>

      {/* Controls */}
      <div className="pv-controls">
        <div className="pv-filter-tabs">
          <button className={`pv-tab ${!filterCat ? 'active' : ''}`} onClick={() => setFilterCat('')}>All</button>
          {categories.map(cat => (
            <button key={cat} className={`pv-tab ${filterCat === cat ? 'active' : ''}`} onClick={() => setFilterCat(cat)}>{cat}</button>
          ))}
        </div>
        {canEdit && (
          <button className="btn-primary" onClick={() => setAdding(true)}><Plus size={15} /> Add Component</button>
        )}
      </div>

      {/* Add form */}
      {adding && canEdit && (
        <div className="pv-add-form fade-in">
          <div className="pv-add-row">
            <input autoFocus placeholder="Component name (e.g. ESP32 DevKit)" value={newName} onChange={e => setNewName(e.target.value)} onKeyDown={e => e.key === 'Enter' && addComponent()} className="pv-add-name" />
            <input type="number" min={1} placeholder="Qty" value={newQty} onChange={e => setNewQty(e.target.value)} className="pv-add-qty" />
            <input placeholder="Category (e.g. MCU, Sensor)" value={newCat} onChange={e => setNewCat(e.target.value)} className="pv-add-cat" />
          </div>
          <div className="pv-add-actions">
            <button className="btn-primary" onClick={addComponent}>Add</button>
            <button className="btn-ghost" onClick={() => { setAdding(false); setNewName(''); setNewQty(1); setNewCat(''); }}>Cancel</button>
          </div>
        </div>
      )}

      {/* Component list */}
      {components.length === 0 ? (
        <div className="pv-empty"><ShoppingCart size={40} /><p>No components yet. {canEdit ? 'Add your first component!' : 'The owner hasn\'t added any yet.'}</p></div>
      ) : filteredComponents.length === 0 ? (
        <div className="pv-empty"><AlertCircle size={32} /><p>No components in this category.</p></div>
      ) : (
        <div className="pv-comp-list">
          <div className="pv-comp-header">
            <span>Component</span>
            <span className="pv-hd-prices">Prices by Store</span>
            <span className="pv-hd-total">Line Total</span>
            <span className="pv-hd-actions"></span>
          </div>
          {filteredComponents.map((comp, i) => (
            <ComponentRow
              key={comp.id}
              comp={comp}
              globalStore={globalStore}
              stores={STORES}
              index={i}
              canEdit={canEdit}
              onUpdate={(changes) => updateComponent(comp.id, changes)}
              onDelete={() => deleteComponent(comp.id)}
            />
          ))}
        </div>
      )}

      {/* Progress */}
      {components.length > 0 && (
        <div className="pv-progress-bar-wrap">
          <div className="pv-progress-label">
            <Check size={13} /> Purchase Progress: {checkedCount}/{components.length}
          </div>
          <div className="pv-progress-track">
            <div className="pv-progress-fill" style={{ width: `${components.length > 0 ? (checkedCount / components.length) * 100 : 0}%` }} />
          </div>
        </div>
      )}

      </div>{/* end pv-content */}
      {panel && (
        <div className="pv-chat-panel">
          {panel === 'chat' && <ChatPanel project={project} onClose={() => setPanel(null)} />}
          {panel === 'ai' && (
            <GeminiPanel
              project={{ ...project, components }}
              canEdit={canEdit}
              onClose={() => setPanel(null)}
              onApplyAction={(action) => {
                if (action.type === 'add') {
                  const newComps = action.components.map(c => ({
                    id: genId(),
                    name: c.name || 'Unnamed',
                    quantity: c.quantity || 1,
                    category: c.category || '',
                    notes: c.notes || '',
                    prices: [],
                    links: {},
                    selectedStore: '',
                    checked: false,
                  }));
                  setAndSave([...components, ...newComps]);
                } else if (action.type === 'update') {
                  const updated = components.map(c => {
                    const match = action.components.find(a => a.id === c.id);
                    if (!match) return c;
                    return { ...c, ...Object.fromEntries(Object.entries(match).filter(([k]) => k !== 'id')) };
                  });
                  setAndSave(updated);
                } else if (action.type === 'delete') {
                  const ids = new Set(action.components.map(a => a.id));
                  setAndSave(components.filter(c => !ids.has(c.id)));
                }
              }}
            />
          )}
        </div>
      )}
      {showExport && (
        <ExportCard project={{ ...project, components }} globalStore={globalStore} totalSelected={totalSelected} stores={STORES} onClose={() => setShowExport(false)} />
      )}
      {showCollab && (
        <CollabModal project={project} currentUser={currentUser} onClose={() => setShowCollab(false)} />
      )}
    </div>
  );
}
