import React, { useState, useEffect, useRef } from 'react';
import { Send, X, MessageCircle, ChevronDown, ArrowLeft, Lock } from 'lucide-react';
import {
  useChatMessages, sendChatMessage,
  useDMs, useDMMessages, sendDMMessage, getOrCreateDM, dmId,
} from '../hooks/useProjects';
import { useAuth } from '../contexts/AuthContext';
import './ChatPanel.css';

export default function ChatPanel({ project, onClose }) {
  const { currentUser } = useAuth();
  const [tab, setTab] = useState('group'); // 'group' | 'dms'
  const [activeDMId, setActiveDMId] = useState(null);

  const members = Object.entries(project.members || {})
    .map(([uid, info]) => ({ uid, ...info }))
    .filter(m => m.uid !== currentUser.uid);

  async function openDM(otherMember) {
    const names  = { [currentUser.uid]: currentUser.displayName || currentUser.email, [otherMember.uid]: otherMember.name || otherMember.email };
    const photos = { [currentUser.uid]: currentUser.photoURL || '', [otherMember.uid]: otherMember.photoURL || '' };
    const id = await getOrCreateDM(
      currentUser.uid, otherMember.uid,
      project.id, project.name,
      names, photos
    );
    setActiveDMId(id);
    setTab('dm-thread');
  }

  return (
    <div className="cp-root fade-in">
      {/* Header */}
      <div className="cp-header">
        <div className="cp-header-left">
          {tab === 'dm-thread' ? (
            <button className="cp-back-btn" onClick={() => { setTab('dms'); setActiveDMId(null); }}>
              <ArrowLeft size={14} />
            </button>
          ) : (
            <MessageCircle size={15} className="cp-header-icon" />
          )}
          <span className="cp-header-title">
            {tab === 'group' ? 'Team Chat' : tab === 'dms' ? 'Direct Messages' : 'Direct Message'}
          </span>
          {tab === 'group' && (
            <span className="cp-header-sub">{Object.keys(project.members || {}).length} members</span>
          )}
        </div>
        <button className="cp-close" onClick={onClose}><X size={16} /></button>
      </div>

      {/* Tabs (only show when not in a thread) */}
      {tab !== 'dm-thread' && (
        <div className="cp-tabs">
          <button className={`cp-tab ${tab === 'group' ? 'active' : ''}`} onClick={() => setTab('group')}>Group</button>
          <button className={`cp-tab ${tab === 'dms' ? 'active' : ''}`} onClick={() => setTab('dms')}>
            Direct Messages {members.length > 0 && <span className="cp-tab-count">{members.length}</span>}
          </button>
        </div>
      )}

      {/* Content */}
      {tab === 'group' && (
        <GroupChat project={project} currentUser={currentUser} />
      )}
      {tab === 'dms' && (
        <DMList members={members} currentUser={currentUser} project={project} onOpen={openDM} />
      )}
      {tab === 'dm-thread' && activeDMId && (
        <DMThread dmId={activeDMId} currentUser={currentUser} project={project} />
      )}
    </div>
  );
}

// ─── Group Chat ───────────────────────────────────────────────────

function GroupChat({ project, currentUser }) {
  const messages = useChatMessages(project.id);
  const [text, setText] = useState('');
  const [sending, setSending] = useState(false);
  const [atBottom, setAtBottom] = useState(true);
  const bottomRef = useRef(null);
  const scrollRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, []);
  useEffect(() => { if (atBottom) bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, atBottom]);

  async function send() {
    if (!text.trim() || sending) return;
    setSending(true);
    try {
      await sendChatMessage(project.id, {
        senderId: currentUser.uid,
        senderName: currentUser.displayName || currentUser.email.split('@')[0],
        senderPhoto: currentUser.photoURL || '',
        text,
      });
      setText(''); setAtBottom(true);
    } catch (e) { console.error(e); }
    setSending(false);
  }

  function onKey(e) { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); } }

  return (
    <MessageArea
      messages={messages}
      currentUser={currentUser}
      text={text}
      setText={setText}
      sending={sending}
      onSend={send}
      onKey={onKey}
      bottomRef={bottomRef}
      scrollRef={scrollRef}
      inputRef={inputRef}
      atBottom={atBottom}
      setAtBottom={setAtBottom}
      emptyText="No messages yet. Start the conversation!"
    />
  );
}

// ─── DM List ──────────────────────────────────────────────────────

function DMList({ members, currentUser, project, onOpen }) {
  const allDMs = useDMs(currentUser.uid);
  // Only show DMs scoped to this project
  const projectDMs = allDMs.filter(d => d.projectId === project.id);

  function getLastMsg(uid) {
    const id = dmId(currentUser.uid, uid, project.id);
    return projectDMs.find(d => d.id === id);
  }

  if (members.length === 0) {
    return (
      <div className="cp-dm-empty">
        <Lock size={28} />
        <p>No other members yet.</p>
        <p className="cp-empty-sub">Invite teammates to start private conversations.</p>
      </div>
    );
  }

  return (
    <div className="cp-dm-list">
      {members.map(m => {
        const dm = getLastMsg(m.uid);
        return (
          <button key={m.uid} className="cp-dm-row" onClick={() => onOpen(m)}>
            <div className="cp-dm-avatar">{(m.name || m.email || '?')[0].toUpperCase()}</div>
            <div className="cp-dm-info">
              <div className="cp-dm-name">{m.name || m.email}</div>
              <div className="cp-dm-last">{dm?.lastMessage || 'No messages yet'}</div>
            </div>
            {dm?.lastMessageAt && (
              <div className="cp-dm-time">{formatTime(dm.lastMessageAt)}</div>
            )}
          </button>
        );
      })}
    </div>
  );
}

